// =======================
// 1. Buat Folder
// =======================

$npsn = preg_replace('/[^A-Za-z0-9_\-]/', '_', $values["npsn"]);
$tahun    = preg_replace('/[^0-9]/', '', $values["tahun"]);
$nisn = preg_replace('/[^A-Za-z0-9]/', '', $values["nisn"]);
$nama = preg_replace('/[^A-Za-z0-9]/', '', $values["nama siswa"]);

$folderName = "files/".$npsn."_".$tahun;

if (!is_dir(getabspath($folderName))) {
    mkdir(getabspath($folderName), 0777, true);
}

// =======================
// 2. Field Upload
// =======================

$uploadFields = array("file_scan");

foreach($uploadFields as $field)
{
    if(!empty($values[$field]))
    {
        $fileArray = my_json_decode($values[$field]);

        for($i = 0; $i < count($fileArray); $i++)
        {
            $oldPath = $fileArray[$i]["name"];

            // Format nama file: kolom_semester_tahun.pdf
            $newFileName = $folderName."/".$nama."_".$nisn."_".$tahun.".pdf";

            // Jika sudah ada file lama, hapus
            if(file_exists(getabspath($newFileName))) {
                unlink(getabspath($newFileName));
            }

            rename(getabspath($oldPath), getabspath($newFileName));

            $fileArray[$i]["name"] = $newFileName;
        }

        $values[$field] = my_json_encode($fileArray);
    }
}
return true;

